@custom-variant dark (&:is(.dark *));

:root {
  --radius: 0.375rem;

  --background: oklch(0.973 0.005 95);
  --foreground: oklch(0.235 0.013 68);
  --card: oklch(0.992 0.003 100);
  --card-foreground: oklch(0.235 0.013 68);
  --popover: oklch(0.992 0.003 100);
  --popover-foreground: oklch(0.235 0.013 68);
  --primary: oklch(0.545 0.155 42);
  --primary-foreground: oklch(0.985 0.008 90);
  --secondary: oklch(0.955 0.006 95);
  --secondary-foreground: oklch(0.300 0.012 68);
  --muted: oklch(0.955 0.006 95);
  --muted-foreground: oklch(0.525 0.012 72);
  --accent: oklch(0.945 0.018 62);
  --accent-foreground: oklch(0.300 0.020 55);
  --destructive: oklch(0.475 0.145 28);
  --destructive-foreground: oklch(0.985 0.008 90);
  --border: oklch(0.905 0.008 88);
  --input: oklch(0.905 0.008 88);
  --ring: oklch(0.545 0.155 42);
  --success: oklch(0.520 0.062 138);
  --success-foreground: oklch(0.985 0.008 90);
  --warning: oklch(0.720 0.125 76);
  --warning-foreground: oklch(0.255 0.020 70);

  --font-sans: 'Inter', ui-sans-serif, system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif;
  --font-mono: 'JetBrains Mono', ui-monospace, 'SFMono-Regular', Menlo, Monaco, monospace;
  --font-display: 'Newsreader', 'Iowan Old Style', Georgia, 'Times New Roman', serif;
}

.dark {
  --background: oklch(0.185 0.008 70);
  --foreground: oklch(0.945 0.006 92);
  --card: oklch(0.215 0.009 68);
  --card-foreground: oklch(0.945 0.006 92);
  --popover: oklch(0.215 0.009 68);
  --popover-foreground: oklch(0.945 0.006 92);
  --primary: oklch(0.620 0.155 45);
  --primary-foreground: oklch(0.200 0.020 60);
  --secondary: oklch(0.275 0.010 66);
  --secondary-foreground: oklch(0.945 0.006 92);
  --muted: oklch(0.275 0.010 66);
  --muted-foreground: oklch(0.705 0.012 78);
  --accent: oklch(0.315 0.022 58);
  --accent-foreground: oklch(0.945 0.006 92);
  --destructive: oklch(0.550 0.155 28);
  --destructive-foreground: oklch(0.970 0.008 90);
  --border: oklch(0.980 0.004 90 / 9%);
  --input: oklch(0.980 0.004 90 / 12%);
  --ring: oklch(0.620 0.155 45);
  --success: oklch(0.600 0.070 138);
  --success-foreground: oklch(0.160 0.010 70);
  --warning: oklch(0.750 0.120 78);
  --warning-foreground: oklch(0.200 0.020 70);
}

@theme inline {
  --radius-sm: calc(var(--radius) - 2px);
  --radius-md: calc(var(--radius) - 1px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);

  --font-sans: var(--font-sans);
  --font-mono: var(--font-mono);
  --font-display: var(--font-display);

  --shadow-xs: 0 1px 2px 0 oklch(0 0 0 / 0.04);
  --shadow-sm: 0 1px 2px 0 oklch(0 0 0 / 0.05), 0 1px 1px -0.5px oklch(0 0 0 / 0.03);
  --shadow-md: 0 6px 20px -6px oklch(0 0 0 / 0.10);
  --shadow-lg: 0 16px 40px -12px oklch(0 0 0 / 0.14);

  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-success: var(--success);
  --color-success-foreground: var(--success-foreground);
  --color-warning: var(--warning);
  --color-warning-foreground: var(--warning-foreground);
}

* {
  scrollbar-width: thin;
  scrollbar-color: color-mix(in oklab, var(--muted-foreground) 35%, transparent) transparent;
}

*::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

*::-webkit-scrollbar-button {
  display: none;
  width: 0;
  height: 0;
}

*::-webkit-scrollbar-track {
  background: transparent;
}

*::-webkit-scrollbar-thumb {
  border-radius: 9999px;
  border: 2px solid transparent;
  background-clip: padding-box;
  background-color: color-mix(in oklab, var(--muted-foreground) 35%, transparent);
}

*::-webkit-scrollbar-thumb:hover {
  background-color: color-mix(in oklab, var(--muted-foreground) 60%, transparent);
}

*::-webkit-scrollbar-corner {
  background: transparent;
}

.hb-scrollbar-none {
  scrollbar-width: none;
  -ms-overflow-style: none;
}
.hb-scrollbar-none::-webkit-scrollbar {
  display: none;
}
